    62→static void test_representative_100(void)
    63→{
    64→    /* --- Section 1: Special IEEE 754 values (7) --- */
    65→    emit(0.0f);
    66→    emit(-0.0f);
    67→    emit_u(0x7fc00000u);  /* qNaN */
    68→    emit_u(0x7f800001u);  /* sNaN */
    69→    emit_u(0xffc00000u);  /* -qNaN */
    70→    emit_u(0x7f800000u);  /* +Inf */
    71→    emit_u(0xff800000u);  /* -Inf */
    72→
    73→    /* --- Section 2: Subnormal (denormal) values (6) --- */
    74→    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    75→    emit_u(0x80000001u);  /* min negative subnormal */
    76→    emit_u(0x00400000u);  /* mid subnormal */
    77→    emit_u(0x80400000u);  /* mid negative subnormal */
    78→    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    79→    emit_u(0x807fffffu);  /* max negative subnormal */
    80→
    81→    /* --- Section 3: Normal boundary values (6) --- */
    82→    emit(FLT_MIN);                /* smallest positive normal: 0x00800000 */
    83→    emit(-FLT_MIN);               /* smallest negative normal */
    84→    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    85→    emit_u(0x7f7fffffu);          /* FLT_MAX */
    86→    emit_u(0xff7fffffu);          /* -FLT_MAX */
    87→    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */
    88→
    89→    /* --- Section 4: Near 1.0 ULP density (8) --- */
    90→    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    91→    emit(1.0f);           /* 1.0: 0x3f800000 */
    92→    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    93→    emit_u(0x3f7ffff0u);  /* several ULPs below 1.0 */
    94→    emit_u(0x3f800010u);  /* several ULPs above 1.0 */
    95→    emit(-1.0f);          /* -1.0: 0xbf800000 */
    96→    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    97→    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */
    98→
    99→    /* --- Section 5: Exponent switching points (10) --- */
   100→    emit_u(0x3f000000u);  /* 0.5 */
   101→    emit_u(0xbf000000u);  /* -0.5 */
   102→    emit_u(0x3effffffu);  /* one ULP below 0.5 */
   103→    emit_u(0x3f000001u);  /* one ULP above 0.5 */
   104→    emit_u(0x40000000u);  /* 2.0 */
   105→    emit_u(0xc0000000u);  /* -2.0 */
   106→    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
   107→    emit_u(0x40000001u);  /* one ULP above 2.0 */
   108→    emit_u(0x3e800000u);  /* 0.25 */
   109→    emit_u(0xbe800000u);  /* -0.25 */
   110→
   111→    /* --- Section 6: Power-of-2 values positive and negative (14) --- */
   112→    emit_u(0x3e000000u);  /* 0.125 = 2^-3 */
   113→    emit_u(0xbe000000u);  /* -0.125 */
   114→    emit_u(0x40800000u);  /* 4.0 = 2^2 */
   115→    emit_u(0xc0800000u);  /* -4.0 */
   116→    emit_u(0x41000000u);  /* 8.0 = 2^3 */
   117→    emit_u(0xc1000000u);  /* -8.0 */
   118→    emit_u(0x41800000u);  /* 16.0 = 2^4 */
   119→    emit_u(0xc1800000u);  /* -16.0 */
   120→    emit_u(0x42000000u);  /* 32.0 = 2^5 */
   121→    emit_u(0xc2000000u);  /* -32.0 */
   122→    emit_u(0x42800000u);  /* 64.0 = 2^6 */
   123→    emit_u(0xc2800000u);  /* -64.0 */
   124→    emit_u(0x43000000u);  /* 128.0 = 2^7 */
   125→    emit_u(0xc3000000u);  /* -128.0 */
   126→
   127→    /* --- Section 7: Fractional values both signs (14) --- */
   128→    emit(0.1f);
   129→    emit(-0.1f);
   130→    emit(0.375f);
   131→    emit(-0.375f);
   132→    emit(0.625f);
   133→    emit(-0.625f);
   134→    emit(0.75f);
   135→    emit(-0.75f);
   136→    emit(0.875f);
   137→    emit(-0.875f);
   138→    emit(0.999f);
   139→    emit(-0.999f);
   140→    emit(1.5f);
   141→    emit(-1.5f);
   142→
   143→    /* --- Section 8: Large values (10) --- */
   144→    emit(1.0e6f);
   145→    emit(-1.0e6f);
   146→    emit(1.0e10f);
   147→    emit(-1.0e10f);
   148→    emit(1.0e20f);
   149→    emit(-1.0e20f);
   150→    emit(1.0e30f);
   151→    emit(-1.0e30f);
   152→    emit_u(0x7f000000u);  /* 2^126: large normal, half of FLT_MAX exponent range */
   153→    emit_u(0xff000000u);  /* -2^126 */
   154→
   155→    /* --- Section 9: Very small normals (10) --- */
   156→    emit(1.0e-10f);
   157→    emit(-1.0e-10f);
   158→    emit(1.0e-20f);
   159→    emit(-1.0e-20f);
   160→    emit(1.0e-30f);
   161→    emit(-1.0e-30f);
   162→    emit(1.0e-38f);
   163→    emit(-1.0e-38f);
   164→    emit_u(0x00800002u);  /* two ULPs above FLT_MIN */
   165→    emit_u(0x80800002u);  /* two ULPs above -FLT_MIN (toward zero) */
   166→
   167→    /* --- Section 10: Arbitrary sign-bit stress patterns (15) --- */
   168→    emit_u(0x40490fdbu);  /* pi: 0x40490fdb */
   169→    emit_u(0xc0490fdbu);  /* -pi */
   170→    emit_u(0x3fc90fdbu);  /* pi/2: 0x3fc90fdb */
   171→    emit_u(0xbfc90fdbu);  /* -pi/2 */
   172→    emit_u(0x3f317218u);  /* ln2: 0x3f317218 */
   173→    emit_u(0xbf317218u);  /* -ln2 */
   174→    emit_u(0x40c90fdbu);  /* 2*pi: 0x40c90fdb */
   175→    emit_u(0xc0c90fdbu);  /* -2*pi */
   176→    emit_u(0x42b17218u);  /* exp overflow threshold ~88.7: 0x42b17218 */
   177→    emit_u(0xc2b17218u);  /* negative exp overflow threshold */
   178→    emit_u(0x3f490fdbu);  /* pi/4: 0x3f490fdb */
   179→    emit_u(0xbf490fdbu);  /* -pi/4 */
   180→    emit_u(0x3ec90fdbu);  /* pi/8: 0x3ec90fdb */
   181→    emit_u(0xbec90fdbu);  /* -pi/8 */
   182→    emit_u(0x55555555u);  /* arbitrary alternating bit pattern with positive sign */
   183→}
