   187→/* 7. Sweep [-4*pi, 4*pi] in 200 steps */
   188→#ifndef EN_PERF
   189→static void test_sweep(void)
   190→{
   191→    float hi = 4.0f * 3.14159265358979323846f;
   192→    int nsteps = 200;
   193→    float step = (2.0f * hi) / (float)nsteps;
   194→
   195→    for (int i = 0; i <= nsteps; i++)
   196→        emit(-hi + (float)i * step);
   197→}
   198→
   199→/* 8. Sample [-1, 1] every 4194304 ULP (~500 cases) */
   200→static void test_exhaustive_small(void)
   201→{
   202→    uint32_t start = 0xbf800000u; /* -1.0 */
   203→    uint32_t end = 0x3f800000u;   /* 1.0 */
   204→
   205→    for (uint32_t b = start; b <= end; b += 2097152)
   206→        emit_u(b);
   207→}
   208→#endif
   209→
   210→/* ------------------------------------------------------------------ */
